-- Add the complete Sesios ingredient reference to the DM-editable Hearthcraft catalogue.
-- This migration also links existing dishes to their key ingredients.

alter table public.catalogue_entries
  drop constraint if exists catalogue_entries_category_check;

alter table public.catalogue_entries
  add constraint catalogue_entries_category_check
  check (
    category in (
      'traits',
      'conditions',
      'items',
      'food_dishes',
      'food_ingredients',
      'food_rules',
      'crafting_sections'
    )
  );

insert into public.catalogue_entries (category, stable_key, sort_order, data)
select
  'food_ingredients',
  'food_ingredients:' || regexp_replace(lower(entry.item ->> 'category'), '[^a-z0-9]+', '-', 'g') || ':' || regexp_replace(lower(entry.item ->> 'name'), '[^a-z0-9]+', '-', 'g'),
  entry.ordinality - 1,
  entry.item
from jsonb_array_elements($ingredients$[{"name":"Canal Mint","category":"Herb & Plant","region":"Asura","mainUse":"Cooling garnish and digestive tea","notes":"Used in student cafes, canal kitchens, and light fish broths. It grows in clay troughs beside clean channels.","role":"Keeper Crop"},{"name":"Aesper Sage","category":"Herb & Plant","region":"Asura","mainUse":"Mana-stabilizing seasoning","notes":"Added sparingly to foods cooked near active conduits. Overuse gives food a metallic aftertaste.","role":"Keeper Crop"},{"name":"Silver Reed","category":"Herb & Plant","region":"Asura, Fittoa","mainUse":"Purity test and broth stirrer","notes":"A reed utensil rather than a spice. It darkens in unsafe Fittoan milk or mana-tainted water.","role":"Keeper Crop"},{"name":"Blue Fen Thyme","category":"Herb & Plant","region":"Asura","mainUse":"Fish, curd, and glasshouse vegetables","notes":"A controlled herb crop used by formal kitchens that want flavor without visible rusticity.","role":"Keeper Crop"},{"name":"Prismbloom Pollen","category":"Herb & Plant","region":"Asura","mainUse":"Honey culture and pastry dust","notes":"Gathered from Prismbee hives. Conductive wax and resin are more valuable than the pollen itself.","role":"Keeper Crop"},{"name":"Smokeleaf","category":"Herb & Plant","region":"Ronoa","mainUse":"Preservation and winter stews","notes":"Hung in smokehouses with fish and Brumox cuts. It tastes harsh unless cooked for hours.","role":"Keeper Crop"},{"name":"Frostmarjor","category":"Herb & Plant","region":"Ronoa","mainUse":"Cold-weather tea and game sauce","notes":"A bitter mountain herb crushed into Skalven preserves and hunting meals.","role":"Keeper Crop"},{"name":"Cairnwort","category":"Herb & Plant","region":"Ronoa","mainUse":"Burial rites and sickness care","notes":"Burned beside sickbeds during White-Lung recovery and carried by guides crossing old cairn roads.","role":"Keeper Crop"},{"name":"Ironmoss","category":"Herb & Plant","region":"Ronoa","mainUse":"Mineral tonic and trail poultice","notes":"Scraped from stone near northern springs. Not eaten raw. Brewed with broth or pressed into bandages.","role":"Keeper Crop"},{"name":"Hearth Nettle","category":"Herb & Plant","region":"Ronoa","mainUse":"Goose fat cakes and winter greens","notes":"Stinging leaves softened in fat. Poor households use it to stretch grain meals.","role":"Keeper Crop"},{"name":"Charcoal Root","category":"Herb & Plant","region":"Fittoa","mainUse":"Detox wash, ash-sickness treatment, broth base","notes":"The standard field ingredient for red ash exposure. Boiled, crushed, or rubbed into water filters.","role":"Keeper Crop"},{"name":"Ashbitter","category":"Herb & Plant","region":"Fittoa","mainUse":"Mask tea and nausea control","notes":"Keeps travelers from vomiting under ash exposure. It stains cups red-grey.","role":"Keeper Crop"},{"name":"Bellweed","category":"Herb & Plant","region":"Fittoa","mainUse":"Warning charm and dangerous tea","notes":"Seed pods click in wind. Camp cooks avoid brewing it unless a guide approves the harvest site.","role":"Keeper Crop"},{"name":"Redmask Reed","category":"Herb & Plant","region":"Fittoa","mainUse":"Filter fiber and camp bundles","notes":"Woven into mask linings and water strainers. It must be dried outside dense mist.","role":"Keeper Crop"},{"name":"Memory Nettle","category":"Herb & Plant","region":"Fittoa","mainUse":"Forbidden ritual garnish","notes":"Used with Telleth in black-market memory food. Legal cooks refuse it.","role":"Keeper Crop"},{"name":"Grave Sage","category":"Herb & Plant","region":"Karrnath","mainUse":"Marrow dishes and funeral soup","notes":"Its smoke covers the scent of bone stock. Gravekeepers also burn it after contaminated burials.","role":"Keeper Crop"},{"name":"Vigil Thyme","category":"Herb & Plant","region":"Karrnath","mainUse":"Night-watch tea","notes":"Served during funeral watches with Blackwake broth to keep mourners awake without loud speech.","role":"Keeper Crop"},{"name":"Marrowleaf","category":"Herb & Plant","region":"Karrnath","mainUse":"Rich sauces and anti-rot poultices","notes":"A dark leaf bruised into vinegar before being served with Duskhide marrow.","role":"Keeper Crop"},{"name":"Black Salt Grass","category":"Herb & Plant","region":"Karrnath","mainUse":"Pickling and ration salt","notes":"Ash-black blades harvested from brackish gravefields. Heavily regulated.","role":"Keeper Crop"},{"name":"Ledgerbloom","category":"Herb & Plant","region":"Karrnath","mainUse":"Contract rites and bitter dye","notes":"Pressed into ink for estate food ledgers and death-related obligations.","role":"Keeper Crop"},{"name":"River Hyssop","category":"Herb & Plant","region":"Shirone","mainUse":"Fish marinade and fever water","notes":"Used with Nayara in temple kitchens and river-clay medicine.","role":"Keeper Crop"},{"name":"Pilgrim Cress","category":"Herb & Plant","region":"Shirone","mainUse":"Flatbread, travel greens, temple soup","notes":"Grows near maintained pilgrim roads. Harvesting too much from shrine beds is fined.","role":"Keeper Crop"},{"name":"Halo Reed","category":"Herb & Plant","region":"Shirone","mainUse":"Oath seals and aromatic steam","notes":"Burned with Sunhive wax during meals of formal reconciliation.","role":"Keeper Crop"},{"name":"Nayara Leaf","category":"Herb & Plant","region":"Shirone","mainUse":"Oil, peel, marinade, bright sauces","notes":"The leaf is less prestigious than the fruit but more common in kitchens.","role":"Keeper Crop"},{"name":"White Canal Basil","category":"Herb & Plant","region":"Shirone","mainUse":"Yoghurt, fish stew, canal vegetables","notes":"A soft herb grown beside temple canals and used in public kitchens.","role":"Keeper Crop"},{"name":"Barkmint","category":"Herb & Plant","region":"Milis","mainUse":"Honey tea and forest medicine","notes":"Tended near Barkbee hives. The grove, not the beekeeper, is considered the first owner.","role":"Keeper Crop"},{"name":"Rootlace","category":"Herb & Plant","region":"Milis","mainUse":"Stew thickener and binding poultice","notes":"A thin root-vine used in dumplings, medicinal wraps, and forest trail soups.","role":"Keeper Crop"},{"name":"Rainmoss","category":"Herb & Plant","region":"Milis","mainUse":"Cold compress and smoked fish lining","notes":"Laid beneath Rootfin trout during forest smoking. Also used to cool fevered skin.","role":"Keeper Crop"},{"name":"Grove Fennel","category":"Herb & Plant","region":"Milis","mainUse":"Clan feasts and animal digestion","notes":"Fed to Bramblebacks before long forest travel and chopped into feast breads.","role":"Keeper Crop"},{"name":"Mooncap","category":"Herb & Plant","region":"Milis","mainUse":"Night stew and dream caution","notes":"A pale forest fungus. Safe only when gathered from approved tree-lines.","role":"Keeper Crop"},{"name":"Well Coriander","category":"Herb & Plant","region":"Begaritt","mainUse":"Cooling bowls and caravan cheese","notes":"Grown in shaded cistern niches. Never harvested without waterkeeper approval.","role":"Keeper Crop"},{"name":"Glasssage","category":"Herb & Plant","region":"Begaritt","mainUse":"Water testing and bitter tea","notes":"Leaves go limp in poisoned cisterns. The tea is unpleasant but trusted.","role":"Keeper Crop"},{"name":"Shade Cumin","category":"Herb & Plant","region":"Begaritt","mainUse":"Preserved meat and desert stew","notes":"A low shrub spice that masks old fat and Khasar cheese sharpness.","role":"Keeper Crop"},{"name":"Khezir Peel","category":"Herb & Plant","region":"Begaritt","mainUse":"Syrup, incense, meat preservation","notes":"The oil-heavy peel is more useful than the bitter fruit itself.","role":"Keeper Crop"},{"name":"Starflower Anise","category":"Herb & Plant","region":"Begaritt","mainUse":"Festival cakes and prophecy tea","notes":"Harvested under recorded star dates, especially near Ishkara orchards.","role":"Keeper Crop"},{"name":"Cinderleaf","category":"Herb & Plant","region":"Demon Continent","mainUse":"Ash-roasts and firepot stews","notes":"Withstands kiln heat. Used to wrap Gorak fruit, eel, and siege-store meats.","role":"Keeper Crop"},{"name":"Ember Fennel","category":"Herb & Plant","region":"Demon Continent","mainUse":"Animal feed and harsh stew","notes":"Keeps Kharak herds calm in ash winds and cuts the oiliness of Cinder eel.","role":"Keeper Crop"},{"name":"Steam Algae","category":"Herb & Plant","region":"Demon Continent","mainUse":"Thermal pond food and thickener","notes":"Cultivated beside Cinder eels. Soldiers dry it into black-green ration sheets.","role":"Keeper Crop"},{"name":"Taruzh Rind","category":"Herb & Plant","region":"Demon Continent","mainUse":"Pickles, sour sauces, medicinal salts","notes":"Sharper than the fruit pulp. Good cooks use it to wake up heavy ash-roasted food.","role":"Keeper Crop"},{"name":"Ash Salt","category":"Herb & Plant","region":"Demon Continent","mainUse":"Curing, travel rations, fermentation","notes":"A survival ingredient, not a luxury. Villages maintain communal salt jars.","role":"Keeper Crop"},{"name":"Halor Oil","category":"Herb & Plant","region":"Heaven Continent","mainUse":"Healing oil and temple incense","notes":"Rare. Even a drop in a sealed dish changes the price of the meal.","role":"Keeper Crop"},{"name":"Iril Rind","category":"Herb & Plant","region":"Heaven Continent","mainUse":"Sacred dessert flavoring","notes":"Does not freeze properly. Usually shaved, never boiled.","role":"Keeper Crop"},{"name":"Cyrune Leaf","category":"Herb & Plant","region":"Heaven Continent","mainUse":"Moon-wine steeping","notes":"Known mostly through liturgical descriptions and suspect merchant claims.","role":"Keeper Crop"},{"name":"Othal Blossom","category":"Herb & Plant","region":"Heaven Continent","mainUse":"Answered-prayer offerings","notes":"If real, it is treated as evidence rather than seasoning.","role":"Keeper Crop"},{"name":"Veyrin Frostmelt","category":"Herb & Plant","region":"Heaven Continent","mainUse":"Preserved offerings and omen food","notes":"Blue frost scraped from Veyrin storage jars. Mostly counterfeit in ordinary markets.","role":"Keeper Crop"},{"name":"Lysael Pear","category":"Witness Fruit & Produce","region":"Asura","mainUse":"Wine, clear preserves, noble desserts, glazes","notes":"Blue-green pear with silver veins. Best near stable Aesperium conduits.","role":"Witness Fruit"},{"name":"Skalven Berry","category":"Witness Fruit & Produce","region":"Ronoa","mainUse":"Winter preserves, soldier rations, game sauces","notes":"A frost-bearing berry that remains on the branch through early snow.","role":"Witness Fruit"},{"name":"Telleth Fruit","category":"Witness Fruit & Produce","region":"Fittoa","mainUse":"Illegal alchemy, memory rites, black-market food","notes":"Pale fruit with black veins. Some say it rings faintly when cut.","role":"Witness Fruit"},{"name":"Morvane Plum","category":"Witness Fruit & Produce","region":"Karrnath","mainUse":"Funeral wine, vinegar, sauces, fruit leather","notes":"Black plum with deep red flesh, grown in iron-heavy gravefield soil.","role":"Witness Fruit"},{"name":"Nayara Citrus","category":"Witness Fruit & Produce","region":"Shirone","mainUse":"Temple oil, naval provisions, fish marinade, sweet wine","notes":"Striped blue-orange citrus, central to sacred and coastal cooking.","role":"Witness Fruit"},{"name":"Vaelwyn Pear","category":"Witness Fruit & Produce","region":"Milis","mainUse":"Honey wine, wedding feasts, dumplings","notes":"Twin-grown pear. Grove origin matters legally and ritually.","role":"Witness Fruit"},{"name":"Selvara Berry","category":"Witness Fruit & Produce","region":"Milis","mainUse":"Sweet sauces, medicine, ceremonial dye","notes":"Long emerald berry that ripens after heavy forest rain.","role":"Witness Fruit"},{"name":"Orimel Apple","category":"Witness Fruit & Produce","region":"Milis","mainUse":"Winter food, cider, caravan trade","notes":"Mineral-rich apple from dwarven terraces.","role":"Witness Fruit"},{"name":"Brannoc Pod","category":"Witness Fruit & Produce","region":"Milis","mainUse":"Travel food, thick stews, beast feed","notes":"Amber pod with creamy pulp and edible seeds.","role":"Witness Fruit"},{"name":"Heshari Fig","category":"Witness Fruit & Produce","region":"Milis","mainUse":"Pilgrim bread, temple offerings, dried rations","notes":"Pale fig grown in shaded sacred groves.","role":"Witness Fruit"},{"name":"Qasira Fruit","category":"Witness Fruit & Produce","region":"Begaritt","mainUse":"Hydration, caravan supplies, cooling tonics","notes":"Thick-rinded green fruit filled with cold water-pulp.","role":"Witness Fruit"},{"name":"Ishkara Fig","category":"Witness Fruit & Produce","region":"Begaritt","mainUse":"Sweet cakes, prophecy rites, luxury exports","notes":"Bronze fig that ripens only during specific celestial seasons.","role":"Witness Fruit"},{"name":"Zahlun Melon","category":"Witness Fruit & Produce","region":"Begaritt","mainUse":"Candies, wine, noble banquets","notes":"Translucent melon with crisp sugar-like flesh.","role":"Witness Fruit"},{"name":"Khezir Orange","category":"Witness Fruit & Produce","region":"Begaritt","mainUse":"Spice syrup, preserved meat, incense","notes":"Bitter fruit prized for its oil-heavy peel.","role":"Witness Fruit"},{"name":"Tazim Pomegranate","category":"Witness Fruit & Produce","region":"Begaritt","mainUse":"Festival food, medicinal seed oil, marriage rites","notes":"Crimson fruit that ripens underground after rare rains.","role":"Witness Fruit"},{"name":"Gorak Fruit","category":"Witness Fruit & Produce","region":"Demon Continent","mainUse":"Roasting, fermentation, trade preserves","notes":"Black skin, orange flesh, smoky sweetness.","role":"Witness Fruit"},{"name":"Veshkar Fig","category":"Witness Fruit & Produce","region":"Demon Continent","mainUse":"Long-term rations, warrior travel packs","notes":"Dense purple fig that dries naturally on the branch.","role":"Witness Fruit"},{"name":"Taruzh Fruit","category":"Witness Fruit & Produce","region":"Demon Continent","mainUse":"Pickles, sour sauces, medicinal salts","notes":"Sharp green fruit that splits after volcanic rain.","role":"Witness Fruit"},{"name":"Molgra Melon","category":"Witness Fruit & Produce","region":"Demon Continent","mainUse":"Water storage, stew base, animal feed","notes":"Heavy red melon from thermal caves and steam vents.","role":"Witness Fruit"},{"name":"Shaleth Berry","category":"Witness Fruit & Produce","region":"Demon Continent","mainUse":"Dye, wine, fever medicine, poultices","notes":"Small violet berry from black forest edges.","role":"Witness Fruit"},{"name":"Iril Pear","category":"Witness Fruit & Produce","region":"Heaven Continent","mainUse":"Sacred desserts, rites, luxury offerings","notes":"White frost pear with warm golden flesh.","role":"Witness Fruit"},{"name":"Cyrune Grape","category":"Witness Fruit & Produce","region":"Heaven Continent","mainUse":"Divine wine and moonlit rites","notes":"Silver-skinned grape that reflects moonlight.","role":"Witness Fruit"},{"name":"Halor Fruit","category":"Witness Fruit & Produce","region":"Heaven Continent","mainUse":"Temple incense and healing oils","notes":"Small orange fruit with a ring pattern near the stem.","role":"Witness Fruit"},{"name":"Othal Apple","category":"Witness Fruit & Produce","region":"Heaven Continent","mainUse":"Pilgrim legends, answered-prayer offerings","notes":"Red-gold apple said to grow where prayers are answered.","role":"Witness Fruit"},{"name":"Veyrin Berry","category":"Witness Fruit & Produce","region":"Heaven Continent","mainUse":"Sky-memory relic and preserved offerings","notes":"Translucent blue berry preserved in ice.","role":"Witness Fruit"},{"name":"Vellhorn Cattle","category":"Livestock","region":"Asura","mainUse":"Milk, cheese, draught work","secondaryUse":"Pale hide, rich manure, mana-warning behavior","marketStatus":"Common in Asuran estates","role":"Herd Ingredient"},{"name":"Brumoxen","category":"Livestock","region":"Ronoa","mainUse":"Sled pulling, winter meat, milk","secondaryUse":"Fur-lined hides, salted butter, mountain hauling","marketStatus":"Common but communally controlled","role":"Herd Ingredient"},{"name":"Hushbacks","category":"Livestock","region":"Fittoa","mainUse":"Lichen grazing, milk, safe-route warning","secondaryUse":"Camp survival, ashland scouting","marketStatus":"Scarce, rarely exported","role":"Herd Ingredient"},{"name":"Duskhide Cattle","category":"Livestock","region":"Karrnath","mainUse":"Beef, marrow, black leather","secondaryUse":"Fertilizer, military ration paste","marketStatus":"Regulated by noble estates","role":"Herd Ingredient"},{"name":"Reedhorns","category":"Livestock","region":"Shirone","mainUse":"Wetland ploughing, milk, river transport","secondaryUse":"Leather, yoghurt, temple estate labor","marketStatus":"Common in riverlands","role":"Herd Ingredient"},{"name":"Khasar","category":"Livestock","region":"Begaritt","mainUse":"Desert travel, water carriage","secondaryUse":"Wool, sour milk, dried dung fuel","marketStatus":"Valuable, tied to Water-Names","role":"Herd Ingredient"},{"name":"Kharak","category":"Livestock","region":"Demon Continent","mainUse":"Ashland hauling, siege transport","secondaryUse":"Eggs, meat, hard hide","marketStatus":"Common in fortified settlements","role":"Herd Ingredient"},{"name":"Brambleback","category":"Livestock","region":"Milis","mainUse":"Forest pack animal, orchard grazing","secondaryUse":"Truffle finding, brush clearing","marketStatus":"Clan or grove-controlled","role":"Herd Ingredient"},{"name":"Hearth Geese","category":"Livestock","region":"Ronoa","mainUse":"Eggs, winter fat","secondaryUse":"Down, alarm animals","marketStatus":"Common household animal","role":"Herd Ingredient"},{"name":"Velvet Moths","category":"Livestock","region":"Karrnath","mainUse":"Black shroud-silk","secondaryUse":"Dark dye, funeral thread","marketStatus":"Temple and estate controlled","role":"Herd Ingredient"},{"name":"Prismbees","category":"Livestock","region":"Asura","mainUse":"Honey, conductive wax","secondaryUse":"Spell-component resin","marketStatus":"Urban apiary product","role":"Herd Ingredient"},{"name":"Sunhives","category":"Livestock","region":"Shirone","mainUse":"Golden wax","secondaryUse":"Temple candles, oath seals","marketStatus":"Temple-managed","role":"Herd Ingredient"},{"name":"Barkbees","category":"Livestock","region":"Milis","mainUse":"Forest honey, medicinal propolis","secondaryUse":"Sacred pollination","marketStatus":"Grove-protected","role":"Herd Ingredient"},{"name":"Moonmoths","category":"Livestock","region":"Begaritt","mainUse":"Pale silk","secondaryUse":"Cool-chamber textile craft","marketStatus":"Wealthy oasis trade","role":"Herd Ingredient"},{"name":"Ashmoths","category":"Livestock","region":"Demon Continent","mainUse":"Heat-resistant fiber","secondaryUse":"Kiln cloth, military gloves","marketStatus":"Practical military good","role":"Herd Ingredient"},{"name":"Silverwings","category":"Livestock","region":"Heaven Continent","mainUse":"Feather-silk","secondaryUse":"Relic banners, divine vestments","marketStatus":"Rumored, not normal trade","role":"Herd Ingredient"},{"name":"Vellhorn Milk","category":"Livestock Product","region":"Asura","mainUse":"Clear-white cheese, noble curd, recovery food","source":"Vellhorn cattle","role":"Herd Ingredient"},{"name":"Brumox Butter","category":"Livestock Product","region":"Ronoa","mainUse":"Salted winter fat, ration jars, stew base","source":"Brumoxen","role":"Herd Ingredient"},{"name":"Hushback Milk","category":"Livestock Product","region":"Fittoa","mainUse":"Survival broth, ashland treatment, tested camp dairy","source":"Hushbacks","role":"Herd Ingredient"},{"name":"Duskhide Marrow","category":"Livestock Product","region":"Karrnath","mainUse":"Military ration paste, marrow tartines, grave-road food","source":"Duskhide cattle","role":"Herd Ingredient"},{"name":"Reedhorn Yoghurt","category":"Livestock Product","region":"Shirone","mainUse":"Pilgrim bread topping, temple food, medicinal meals","source":"Reedhorns","role":"Herd Ingredient"},{"name":"Khasar Milk","category":"Livestock Product","region":"Begaritt","mainUse":"Sour desert cheese, caravan food","source":"Khasar","role":"Herd Ingredient"},{"name":"Kharak Eggs","category":"Livestock Product","region":"Demon Continent","mainUse":"Siege stores, ashland baking, durable ration food","source":"Kharak","role":"Herd Ingredient"},{"name":"Barkbee Honey","category":"Livestock Product","region":"Milis","mainUse":"Forest preservation, medicine, ritual sweets","source":"Barkbees","role":"Herd Ingredient"},{"name":"Prismbee Wax","category":"Livestock Product","region":"Asura","mainUse":"Lamp seals, spellwork, urban food storage","source":"Prismbees","role":"Herd Ingredient"},{"name":"Sunhive Wax","category":"Livestock Product","region":"Shirone","mainUse":"Temple candles, oath seals, sacred preservation","source":"Sunhives","role":"Herd Ingredient"},{"name":"Glassfin Carp","category":"Fishery Catch","region":"Asura","mainUse":"Soup stock, canal fish","secondaryUse":"Fertilizer, mana contamination testing","notes":"Scales cloud near mana damage","role":"Tide Ingredient"},{"name":"Hrimchar","category":"Fishery Catch","region":"Ronoa","mainUse":"Smoked fish, winter rations","secondaryUse":"Expedition food, fish cakes","notes":"Caught after first deep freeze","role":"Tide Ingredient"},{"name":"Mirror Eels","category":"Fishery Catch","region":"Fittoa","mainUse":"Alchemy, rare bait","secondaryUse":"Illegal trade","notes":"Not safe food, may reflect absent faces","role":"Tide Ingredient"},{"name":"Blackwake Lamprey","category":"Fishery Catch","region":"Karrnath","mainUse":"Oil, salt paste, blood broth","secondaryUse":"Funeral vigil food, medicinal broth","notes":"Associated with death rites","role":"Tide Ingredient"},{"name":"Azurefin","category":"Fishery Catch","region":"Shirone","mainUse":"Grilled fish, stew","secondaryUse":"Dried naval ration","notes":"Sold fresh at Waterkeep each dawn","role":"Tide Ingredient"},{"name":"Rootfin Trout","category":"Fishery Catch","region":"Milis","mainUse":"River cooking, forest smoking","secondaryUse":"Festival dishes","notes":"Cannot be taken near sacred groves","role":"Tide Ingredient"},{"name":"Cistern Glassfish","category":"Fishery Catch","region":"Begaritt","mainUse":"Food, mosquito control","secondaryUse":"Water quality warning","notes":"Raised in stepwells","role":"Tide Ingredient"},{"name":"Cinder Eels","category":"Fishery Catch","region":"Demon Continent","mainUse":"Smoked meat, oil","secondaryUse":"Thermal pond farming","notes":"Survive volcanic runoff pools","role":"Tide Ingredient"},{"name":"Bellfin","category":"Fishery Catch","region":"Heaven Continent","mainUse":"Rumored sacred food","secondaryUse":"Frost preservation, divine omen","notes":"No verified common-market specimen","role":"Tide Ingredient"},{"name":"Glassfin Stock","category":"Fishery Product","region":"Asura","mainUse":"Asuran soups, canal-worker meals, water-testing kitchens","source":"Glassfin carp","role":"Tide Ingredient"},{"name":"Hrimchar Smoke","category":"Fishery Product","region":"Ronoa","mainUse":"Ronoan ration cakes, winter trail food","source":"Hrimchar","role":"Tide Ingredient"},{"name":"Mirror Eel Flesh","category":"Fishery Product","region":"Fittoa","mainUse":"Alchemical reagent, forbidden bait, black-market curiosity","source":"Mirror eels","role":"Tide Ingredient"},{"name":"Blackwake Oil","category":"Fishery Product","region":"Karrnath","mainUse":"Lamp oil, medicine, funeral rites","source":"Blackwake lamprey","role":"Tide Ingredient"},{"name":"Blackwake Salt Paste","category":"Fishery Product","region":"Karrnath","mainUse":"Preserved Karrnathi food, soldier ration additive","source":"Blackwake lamprey","role":"Tide Ingredient"},{"name":"Azurefin Fillets","category":"Fishery Product","region":"Shirone","mainUse":"Street skewers, temple stews, naval provisions","source":"Azurefin","role":"Tide Ingredient"},{"name":"Rootfin Smoke","category":"Fishery Product","region":"Milis","mainUse":"Milis feast food, preserved forest ration","source":"Rootfin trout","role":"Tide Ingredient"},{"name":"Glassfish Shoal","category":"Fishery Product","region":"Begaritt","mainUse":"Stepwell food, mosquito control, poisoned-water warning","source":"Cistern glassfish","role":"Tide Ingredient"},{"name":"Cinder Eel Oil","category":"Fishery Product","region":"Demon Continent","mainUse":"Heat cooking, ashland preservation, lamp fuel","source":"Cinder eels","role":"Tide Ingredient"},{"name":"Bellfin Salt","category":"Fishery Product","region":"Heaven Continent","mainUse":"Mythic frost-preserved offering, Heaven-linked relic food","source":"Bellfin","role":"Tide Ingredient"}]$ingredients$::jsonb)
with ordinality as entry(item, ordinality)
on conflict (category, stable_key) do update
set
  sort_order = excluded.sort_order,
  data = excluded.data;

with dish_ingredient_map(name, ingredients) as (
  values
    ('Lysael Glassfin Parcels', '["Glassfin Carp", "Vellhorn Milk", "Canal Mint", "Lysael Pear"]'::jsonb),
    ('Vellhorn Cloud Curd', '["Vellhorn Milk", "Lysael Pear", "Prismbloom Pollen"]'::jsonb),
    ('Brumox Winter Pot', '["Brumoxen", "Brumox Butter", "Smokeleaf", "Skalven Berry"]'::jsonb),
    ('Hrimchar Smoke-Cakes', '["Hrimchar", "Hrimchar Smoke", "Hearth Geese", "Smokeleaf"]'::jsonb),
    ('Hushback Silver-Reed Broth', '["Hushback Milk", "Charcoal Root", "Silver Reed", "Ashbitter"]'::jsonb),
    ('Telleth Bellbread ⚠', '["Telleth Fruit", "Memory Nettle", "Bellweed"]'::jsonb),
    ('Duskhide Marrow Tartine', '["Duskhide Marrow", "Black Salt Grass", "Morvane Plum", "Grave Sage"]'::jsonb),
    ('Blackwake Vigil Soup', '["Blackwake Lamprey", "Blackwake Salt Paste", "Vigil Thyme", "Morvane Plum"]'::jsonb),
    ('Azurefin Nayara Skewers', '["Azurefin", "Azurefin Fillets", "Nayara Citrus", "River Hyssop"]'::jsonb),
    ('Reedhorn Yoghurt Hearthbread', '["Reedhorn Yoghurt", "Nayara Leaf", "Pilgrim Cress", "White Canal Basil"]'::jsonb),
    ('Vaelwyn Bark-Honey Dumplings', '["Vaelwyn Pear", "Barkbee Honey", "Rootlace"]'::jsonb),
    ('Qasira Well-Bowl', '["Qasira Fruit", "Khezir Peel", "Khasar Milk", "Well Coriander"]'::jsonb),
    ('Gorak Ash-Roast', '["Gorak Fruit", "Cinder Eels", "Taruzh Fruit", "Ash Salt", "Cinderleaf"]'::jsonb),
    ('Iril Candle-Pear ✦', '["Iril Pear", "Iril Rind", "Halor Oil", "Veyrin Frostmelt"]'::jsonb)
)
update public.catalogue_entries as entry
set data = jsonb_set(entry.data, '{ingredients}', mapping.ingredients, true)
from dish_ingredient_map as mapping
where entry.category = 'food_dishes'
  and entry.data ->> 'name' = mapping.name;
